// Time:  O(n^2)
// Space: O(1)

// brute force
class Solution {
public:
    int numberOfCategories(int n, CategoryHandler* categoryHandler) {
        int cnt = 0;
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < i; ++j) {
                if (categoryHandler->haveSameCategory(j, i)) {
                    ++cnt;
                    break;
                }
            }
        }
        return n - cnt;
    }
};

# Time:  O(n^2)
# Space: O(1)

# Definition for a category handler.
class CategoryHandler:
    def haveSameCategory(self, a, b):
        pass


# brute force
class Solution(object):
    def numberOfCategories(self, n, categoryHandler):
        """
        :type n: int
        :type categoryHandler: CategoryHandler
        :rtype: int
        """
        return sum(all(not categoryHandler.haveSameCategory(j, i) for j in xrange(i)) for i in xrange(n))
